mapper.select:
SELECT id, keyword, emotion_type, weight, status, create_time, update_time
FROM emotion_keyword
WHERE id = #{id}

SELECT id, keyword, emotion_type, weight, status, create_time, update_time
FROM emotion_keyword
WHERE keyword = #{keyword}

SELECT id, keyword, emotion_type, weight, status, create_time, update_time
FROM emotion_keyword
WHERE emotion_type = #{emotionType}
ORDER BY emotion_type, weight DESC
LIMIT #{offset}, #{limit}
